// Service Worker for Minihongo PWA
// Cache-first with background revalidation for all assets
// Cache name includes content hash so deploys bust the old cache

// Cache name includes a content hash so a new deploy busts the old cache
const CACHE = 'minihongo-e0b597ee'

// All pages and assets to pre-cache on install (enables full offline use)
// Auto-generated by build.py from actual build output
const PRECACHE = [
  './',
  'static/style.css',
  'static/app.js',
  '_f/',
  '_f/lessons/grammar.html',
  '_f/lessons/texts-dialogs.html',
  '_f/lessons/vocabulary.html',
  '_f/lessons/word-building.html',
  'ja/_f/',
  'ja/_f/lessons/grammar.html',
  'ja/_f/lessons/texts-dialogs.html',
  'ja/_f/lessons/vocabulary.html',
  'ja/_f/lessons/word-building.html',
  'ja/',
  'ja/lessons/grammar.html',
  'ja/lessons/texts-dialogs.html',
  'ja/lessons/vocabulary.html',
  'ja/lessons/word-building.html',
  'lessons/grammar.html',
  'lessons/texts-dialogs.html',
  'lessons/vocabulary.html',
  'lessons/word-building.html',
  'mh/_f/',
  'mh/_f/lessons/grammar.html',
  'mh/_f/lessons/texts-dialogs.html',
  'mh/_f/lessons/vocabulary.html',
  'mh/_f/lessons/word-building.html',
  'mh/',
  'mh/lessons/grammar.html',
  'mh/lessons/texts-dialogs.html',
  'mh/lessons/vocabulary.html',
  'mh/lessons/word-building.html',
]

// -- Lifecycle events ---------------------------------------------------

// Pre-cache all assets on install, then activate immediately
self.addEventListener('install', (e) => {
  e.waitUntil(
    caches.open(CACHE)
      .then((c) => c.addAll(PRECACHE))
      .then(() => self.skipWaiting())
  )
})

// Delete old caches from previous versions, then claim all clients
self.addEventListener('activate', (e) => {
  e.waitUntil(
    caches.keys()
      .then((keys) => Promise.all(keys.filter((k) => k !== CACHE).map((k) => caches.delete(k))))
      .then(() => self.clients.claim())
  )
})

// -- Fetch routing ------------------------------------------------------

self.addEventListener('fetch', (e) => {
  if (e.request.method !== 'GET') return
  if (e.request.url.includes('/audio/')) return
  if (e.request.mode === 'navigate') {
    e.respondWith(handleNavigate(e.request))
  } else {
    e.respondWith(cacheFirst(e.request))
  }
})

// -- Caching strategy ---------------------------------------------------

// Navigation requests: cache -> network -> cached root -> retry page
// Serves cached immediately, revalidates in background for freshness
const handleNavigate = async (request) => {
  const cache = await caches.open(CACHE)
  const cached = await cache.match(request)
  if (cached) {
    fetch(request).then((res) => {
      if (res.ok) cache.put(request, res.clone())
    }).catch(() => null)
    return cached
  }
  try {
    const res = await fetch(request)
    if (res.ok) cache.put(request, res.clone())
    return res
  } catch {
    // Try serving the root page from cache (SPA can route from there)
    const root = await cache.match('/') || await cache.match('/index.html')
    if (root) return root
    // Last resort: minimal retry page
    return new Response(`<!DOCTYPE html><html><head>
      <meta name="viewport" content="width=device-width">
      <script>
        const d=localStorage.getItem('theme')||(matchMedia('(prefers-color-scheme:dark)').matches?'dark':'light');
        document.documentElement.dataset.theme=d
      </script>
      <style>
        :root{--bg:#FFFFFF;--text-muted:#666666}
        [data-theme="dark"]{--bg:#1A1A1A;--text-muted:#999999}
        body{font-family:system-ui;display:flex;justify-content:center;align-items:center;height:100vh;margin:0;background:var(--bg);color:var(--text-muted)}
      </style>
      </head><body><p>Offline. Retrying&hellip;</p>
      <script>addEventListener('online',()=>location.reload());setTimeout(()=>location.reload(),3000)</script>
      </body></html>`, { headers: { 'Content-Type': 'text/html' } })
  }
}

// Cache-first with background revalidation for static assets
const cacheFirst = async (request) => {
  const cache = await caches.open(CACHE)
  const cached = await cache.match(request)

  const refresh = fetch(request).then((res) => {
    if (res.ok) cache.put(request, res.clone())
    return res
  }).catch(() => null)

  return cached ?? (await refresh) ?? new Response('Offline', { status: 503 })
}
